mapper.insert:
INSERT INTO TICKET_TYPE
	( TYPE_ID
	, TYPE_NM
	, SORT_ORDER
	, USE_YN
	, REG_DT )
VALUES
	( #{typeId}
	, #{typeNm}
	, #{sortOrder}
	, #{useYn}
	, GETDATE() )

mapper.update:
UPDATE TICKET_TYPE
SET TYPE_NM    = #{typeNm}
  , SORT_ORDER = #{sortOrder}
  , USE_YN     = #{useYn}
WHERE TYPE_ID = #{typeId}

mapper.select:
SELECT TYPE_ID, TYPE_NM, SORT_ORDER, USE_YN, REG_DT
FROM TICKET_TYPE
WHERE TYPE_ID = #{typeId}

SELECT COUNT(*)
FROM TICKET_TYPE
WHERE TYPE_NM = #{typeNm}

	AND TYPE_ID != #{typeId}
